script:
frappe.ui.form.on('DPDP Assessment', {
    refresh(frm) {

        frm.add_custom_button('Regenerate PDF', function() {
            frappe.confirm(
                'Regenerate and re-email the PDF using stored AI content?',
                function() {
                    frappe.call({
                        method: 'dpdp_tool.api.regenerate_pdf',
                        args: { docname: frm.doc.name },
                        callback: function() {
                            frappe.show_alert({ message: 'PDF generation queued — reload in 30s.', indicator: 'blue' });
                            setTimeout(() => frm.reload_doc(), 30000);
                        }
                    });
                }
            );
        }, 'Actions');

        frm.add_custom_button('Re-run AI Analysis', function() {
            frappe.confirm(
                'Re-run both AI calls and regenerate the PDF? This overwrites existing AI content.',
                function() {
                    frappe.call({
                        method: 'dpdp_tool.api.rerun_ai_calls',
                        args: { docname: frm.doc.name },
                        callback: function() {
                            frappe.show_alert({ message: 'AI calls queued — reload in 90s.', indicator: 'blue' });
                            setTimeout(() => frm.reload_doc(), 90000);
                        }
                    });
                }
            );
        }, 'Actions');

    }
});
